<template>
	<view class="z-image-painter-root" id="z-image-painter-root">
		<view class="painter-container" id="painter-container">
			<view class="painter-box" :style="{ height: `${wrapperSize.height}px`, width: `${wrapperSize.width}px` }">
				<uni-icons type="refreshempty" v-if="scale !== 1 || translateX !== 0 || translateY !== 0"
					class="reset-transform" @click="resetTransform" size="30"></uni-icons>



				<view class="painter-wrapper"
					:style="{ height: `${wrapperSize.height}px`, width: `${wrapperSize.width}px`, transform: `scale(${scale}) translate(${translateX}px, ${translateY}px)` }"
					@touchstart="onScaleStart" @touchmove="onScaleMove" @touchend="onScaleEnd"
					@touchcancel="onScaleEnd">
					<image :src="props.src" @load="loadImage" class="main-image" />
					<canvas v-if="props.allowDraw" v-show="!useVirtualCanvas" canvas-id="painter-canvas" type="2d"
						id="painter-canvas" class="painter-canvas" @touchstart="onDrawStart" @touchmove="onDrawMove"
						@touchend="onDrawEnd" @touchcancel="onDrawEnd" />
					<canvas v-if="props.allowDraw && virtualCanvas" v-show="useVirtualCanvas" canvas-id="virtual-canvas"
						type="2d" id="virtual-canvas" class="virtual-canvas" @touchstart="onDrawStart"
						@touchmove="onDrawMove" @touchend="onDrawEnd" @touchcancel="onDrawEnd"
						:style="{ height: `${wrapperSize.height}px`, width: `${wrapperSize.width}px`, transform: `scale(${1 / scale}) translate(${-translateX * scale}px, ${-translateY * scale}px)` }" />
				</view>
			</view>
		</view>
		<canvas v-if="props.allowDraw" id="export-canvas" canvas-id="export-canvas" class="export-canvas" type="2d"
			:style="{ width: `${originImageSize.width}px`, height: `${originImageSize.height}px` }" />
	</view>
</template>

<script setup>
import {
	ref,
	onMounted,
	computed,
	nextTick,
	defineExpose,
	getCurrentInstance
} from 'vue'

const props = defineProps({
	src: {
		type: String
	},
	mode: {
		type: String,
		default: 'aspectFit'
	},
	allowDraw: {
		type: Boolean,
		default: true
	},
	drawColor: {
		type: String,
		default: 'rgba(128, 0, 128, 1)'
	},
	brushSize: {
		type: Number,
		default: 5
	},
	exportOriginSize: {
		type: Boolean,
		default: true
	}
})

// 实测微信小程序canvas缩放会导致已绘制图案偏移，故添加一个虚拟canvas仅作展示，便于了解当前涂抹位置
const virtualCanvas = ref(false);
const scale = ref(1)
const translateX = ref(0)
const translateY = ref(0)
const wrapperSize = ref({
	height: 1,
	width: 1
})
const originImageSize = ref({})

const instance = getCurrentInstance()

onMounted(() => {
	virtualCanvas.value = (process.env.UNI_PLATFORM === 'mp-weixin')
})

const useVirtualCanvas = computed(() => virtualCanvas.value && (scale.value !== 1 || translateX.value !== 0 ||
	translateY.value !== 0))

function loadImage(event) {
	const originHeight = event.detail.height
	const originWidth = event.detail.width
	originImageSize.value = event.detail
	getElementSizeById("painter-container").then(rect => {
		const cWidth = Math.floor(rect.width)
		const cHeight = Math.floor(rect.height)
		if (props.mode === 'scaleToFill') {
			wrapperSize.value = {
				width: cWidth,
				height: cHeight
			}
		} else {
			const baseHeight = cWidth / originWidth * originHeight
			let width, height
			if (baseHeight > cHeight) {
				height = cHeight
				width = cHeight / originHeight * originWidth
			} else {
				width = cWidth
				height = baseHeight
			}
			wrapperSize.value = {
				width: width,
				height: height
			}
		}
		nextTick(() => {
			if (props.allowDraw) {
				initCanvas()
			}
		})
	})
}

let ctx = null
let vCtx = null
// 导出使用单独canvas,并将其放在屏幕外
let eCtx = null

// function initCanvas() {
// 	ctx = uni.createCanvasContext('painter-canvas', instance.proxy)
// 	eCtx = uni.createCanvasContext('export-canvas', instance.proxy)
// 	if (virtualCanvas.value) {
// 		vCtx = uni.createCanvasContext('virtual-canvas', instance.proxy)
// 	}
// }
function initCanvas() {
	// 1. 销毁旧上下文避免内存泄漏
	if (ctx) ctx = null
	if (vCtx) vCtx = null

	// 2. 重新获取上下文
	ctx = uni.createCanvasContext('painter-canvas', instance.proxy)
	eCtx = uni.createCanvasContext('export-canvas', instance.proxy)

	// 3. 微信小程序需延迟确保上下文就绪（50ms防抖）
	setTimeout(() => {
		if (virtualCanvas.value) {
			vCtx = uni.createCanvasContext('virtual-canvas', instance.proxy)
		}
	}, 50)
}

let touchMode = null
const drawHistory = ref([])
let currentPath = []
let lastPoint = {}

function onDrawStart(e) {
	if (!props.allowDraw || !ctx) return
	const count = Array.isArray(e.touches) ? e.touches.length : Object.keys(e.touches).length
	if (count === 1) {
		touchMode = 'draw'
		currentPath = []
		const {
			x,
			y
		} = calcRealCoordinate(e.touches[0].x, e.touches[0].y)
		lastPoint = {
			x: x,
			y: y
		}
	} else {
		// 触点增加，结束draw事件
		if (touchMode === 'draw') {
			onDrawEnd(e)
		}
	}
}

function onDrawMove(e) {
	if (!props.allowDraw || !ctx) return
	const count = Array.isArray(e.touches) ? e.touches.length : Object.keys(e.touches).length
	if (touchMode !== 'draw' || count !== 1) return
	const {
		x,
		y
	} = calcRealCoordinate(e.touches[0].x, e.touches[0].y)
	const seg = {
		x1: lastPoint.x,
		y1: lastPoint.y,
		x2: x,
		y2: y,
		color: props.drawColor,
		size: props.brushSize
	}
	draw(seg, useVirtualCanvas.value ? vCtx : ctx)
	currentPath.push(seg)
	lastPoint = {
		x: x,
		y: y
	}
}

function onDrawEnd(e) {
	if (!props.allowDraw || !ctx) return
	if (touchMode === 'draw') {
		touchMode = null
		if (currentPath.length) {
			drawHistory.value.push([...currentPath])
			currentPath = []
			lastPoint = {}
		}
	}
}

function reDrawVirtualCanvas() {
	if (!vCtx || !useVirtualCanvas.value) return
	vCtx.clearRect(0, 0, 9999, 9999)
	vCtx.draw()
	for (let paths of drawHistory.value) {
		for (let seg of paths) {
			draw(seg, vCtx)
		}
	}
}

function reDraw(needReDraw) {
	if (!ctx || !needReDraw) return
	ctx.clearRect(0, 0, 9999, 9999)
	ctx.draw()
	for (let paths of drawHistory.value) {
		for (let seg of paths) {
			draw(seg, ctx)
		}
	}
}

// function calcVirtualCoordinate(x, y) {
// 	return {
// 		x: (x + translateX.value) * scale.value,
// 		y: (y + translateY.value) * scale.value
// 	}
// }
function calcVirtualCoordinate(x, y) {
  return {
    // 统一转换公式（虚拟坐标 -> 真实坐标）
    x: (x / scale.value) + translateX.value, 
    y: (y / scale.value) + translateY.value
  }
}
function calcRealCoordinate(x, y) {
	if (useVirtualCanvas.value) {
		return {
			x: x / scale.value - translateX.value,
			y: y / scale.value - translateY.value
		}
	}
	return {
		x: x / scale.value,
		y: y / scale.value
	}
}

function draw(seg, context) {
	let x1, x2, y1, y2, size
	if (useVirtualCanvas.value) {
		const p1 = calcVirtualCoordinate(seg.x1, seg.y1)
		const p2 = calcVirtualCoordinate(seg.x2, seg.y2)
		x1 = p1.x
		y1 = p1.y
		x2 = p2.x
		y2 = p2.y
		size = seg.size * scale.value
	} else {
		x1 = seg.x1
		y1 = seg.y1
		x2 = seg.x2
		y2 = seg.y2
		size = seg.size
	}
	context.setLineWidth?.(size)
	context.setStrokeStyle?.(seg.color)
	context.setFillStyle?.(seg.color)
	context.setLineCap?.('round')
	context.setLineJoin?.('round')
	context.beginPath()
	context.moveTo(x1, y1)
	context.lineTo(x2, y2)
	context.stroke()
	context.draw(true)
}

let lastDistance = 0
let lastCenter = {
	x: 0,
	y: 0
}

function onScaleStart(e) {
	const count = e.touches.length
	if (count === 2) {
		touchMode = 'scale'
		lastDistance = getDistance(e.touches)
		lastCenter = getCenter(e.touches)
		return
	}
	if (count > 2) {
		onScaleEnd(e)
	}
}

function onScaleMove(e) {
	const count = e.touches.length
	if (count !== 2 || touchMode !== 'scale') return
	const newDistance = getDistance(e.touches)
	const scaleDelta = newDistance / lastDistance
	scale.value = Math.min(Math.max(scale.value * scaleDelta, 1), 5)
	const newCenter = getCenter(e.touches)
	translateX.value += newCenter.x - lastCenter.x
	translateY.value += newCenter.y - lastCenter.y
	lastDistance = newDistance
	lastCenter = newCenter
}

function onScaleEnd(e) {
	if (touchMode === 'scale') {
		touchMode = null
		lastDistance = 0
		lastCenter = {
			x: 0,
			y: 0
		}
		reDrawVirtualCanvas()
	}
}

function getDistance(touches) {
	const [p1, p2] = touches
	const dx = p2.clientX - p1.clientX
	const dy = p2.clientY - p1.clientY
	return Math.sqrt(dx * dx + dy * dy)
}

function getCenter(touches) {
	const [p1, p2] = touches
	return {
		x: (p1.clientX + p2.clientX) / 2,
		y: (p1.clientY + p2.clientY) / 2
	}
}

function resetTransform() {
	const needReDraw = useVirtualCanvas.value
	if (scale.value === 1 && translateX.value === 0 && translateY.value === 0) return
	scale.value = 1
	translateX.value = 0
	translateY.value = 0
	setTimeout(() => reDraw(needReDraw), 100)
}

// util functions
function getElementSizeById(id) {
	return new Promise(resolve => {
		uni.createSelectorQuery()
			.in(instance?.proxy)
			.select(`#${id}`)
			.boundingClientRect(rect => {
				resolve({
					width: rect.width,
					height: rect.height,
					top: rect.top,
					left: rect.left
				})
			})
			.exec()
	})
}

// function exportImage(exportMode) {
// 	return new Promise((resolve, reject) => {
// 		let width, height, widthRatio, heightRatio
// 		if (props.exportOriginSize) {
// 			width = originImageSize.value.width
// 			height = originImageSize.value.height
// 			widthRatio = wrapperSize.value.width / originImageSize.value.width
// 			heightRatio = wrapperSize.value.height / originImageSize.value.height
// 		} else {
// 			width = wrapperSize.value.width
// 			height = wrapperSize.value.height
// 			widthRatio = 1
// 			heightRatio = 1
// 		}
// 		eCtx.clearRect(0, 0, width, height)
// 		if (exportMode === 'merged') {
// 			eCtx.drawImage(props.src, 0, 0, width, height)
// 			eCtx.draw(true)
// 		}
// 		for (let path of drawHistory.value) {
// 			for (let seg of path) {
// 				eCtx.setLineWidth?.(Math.min(seg.size / widthRatio, seg.size / heightRatio))
// 				eCtx.setStrokeStyle?.(seg.color)
// 				eCtx.setFillStyle?.(seg.color)
// 				eCtx.setLineCap?.('round')
// 				eCtx.setLineJoin?.('round')
// 				eCtx.beginPath()
// 				eCtx.moveTo(seg.x1 / widthRatio, seg.y1 / heightRatio)
// 				eCtx.lineTo(seg.x2 / widthRatio, seg.y2 / heightRatio)
// 				eCtx.stroke()
// 			}
// 		}
// 		eCtx.draw(true)
// 		setTimeout(() => {
// 			uni.canvasToTempFilePath({
// 				canvasId: 'export-canvas',
// 				width,
// 				height,
// 				destWidth: width,
// 				destHeight: height,
// 				fileType: 'jpg',
// 				success(res) {
// 					resolve(res.tempFilePath)
// 					// 你可以返回或 emit 这个路径
// 				},
// 				fail(err) {
// 					console.error('导出失败：', err)
// 					reject(err)
// 				}
// 			}, instance?.proxy)
// 		}, 300)
// 	})
// }

function exportImage(exportMode) {
  return new Promise((resolve, reject) => {
    // 1. 获取画布尺寸（支持原始尺寸/容器尺寸）
    let width, height
    if (props.exportOriginSize) {
      width = originImageSize.value.width
      height = originImageSize.value.height
    } else {
      width = wrapperSize.value.width
      height = wrapperSize.value.height
    }

    // 2. 重置画布状态
    eCtx.setTransform(1, 0, 0, 1, 0, 0)
    eCtx.clearRect(0, 0, width, height)

    // 3. 绘制背景图片（带矩阵变换）
    if (exportMode === 'merged') {
      eCtx.save()
      eCtx.scale(scale.value, scale.value)
      eCtx.translate(translateX.value, translateY.value)
      
      eCtx.drawImage(
        props.src, 
        0, 0, 
        originImageSize.value.width, 
        originImageSize.value.height
      )
      eCtx.restore()
    }

    // 4. 绘制所有笔触（动态调整尺寸）
    for (let path of drawHistory.value) {
      for (let seg of path) {
        eCtx.beginPath()
        eCtx.setLineWidth(seg.size / scale.value) // 根据缩放调整笔触
        eCtx.setStrokeStyle(seg.color)
        eCtx.moveTo(seg.x1 / scale.value, seg.y1 / scale.value)
        eCtx.lineTo(seg.x2 / scale.value, seg.y2 / scale.value)
        eCtx.stroke()
      }
    }

    // 5. 提交绘制并导出
    eCtx.draw(true)
    
    // 6. 延迟导出确保渲染完成
    setTimeout(() => {
      uni.canvasToTempFilePath({
        canvasId: 'export-canvas',
        fileType: 'jpg',
        quality: 0.9, // 导出质量优化
        success(res) {
          resolve(res.tempFilePath)
        },
        fail(err) {
          console.error('导出失败:', err)
          uni.showToast({ title: '导出失败', icon: 'none' })
          reject(err)
        }
      }, instance?.proxy)
    }, 500)
  })
}

function undo() {
	if (drawHistory.value.length < 1) return
	drawHistory.value.pop()
	if (useVirtualCanvas.value) {
		reDrawVirtualCanvas()
	} else {
		reDraw(true)
	}
}

function clear() {
	if (drawHistory.value.length < 1) return
	drawHistory.value = []
	let context = useVirtualCanvas.value ? vCtx : ctx
	context.clearRect(0, 0, 9999, 9999)
	context.draw()
}

defineExpose({
	exportImage,
	undo,
	clear
})
</script>
<style>
.z-image-painter-root {
	height: 100%;
	width: 100%;
	touch-action: none;
}

.export-canvas {
	position: absolute;
	top: -9999px;
	/* 放到屏幕外 */
	left: -9999px;
	pointer-events: none;
	z-index: 50;
}

.painter-container {
	height: 100%;
	width: 100%;
	display: flex;
	align-items: center;
	/* 垂直居中 */
	justify-content: center;
	/* 水平居中 */
	overflow: hidden;
}

.painter-box {
	position: relative;
	overflow: hidden;
}

.reset-transform {
	position: absolute;
	right: 0;
	top: 0;
	z-index: 10;
}

.painter-wrapper {
	position: relative;
	transform-origin: left top;
	pointer-events: auto;
}

.main-image {
	position: absolute;
	height: 100%;
	width: 100%;
	z-index: 5;
	left: 0;
	top: 0;
}

.painter-canvas {
	position: absolute;
	width: 100%;
	height: 100%;
	z-index: 6;
	left: 0;
	top: 0;
	pointer-events: auto;
}

.virtual-canvas {
	position: absolute;
	z-index: 6;
	pointer-events: auto;
	transform-origin: left top;
}
</style>